#!/usr/bin/env python3
"""fix4.py — spam filter + URL resolve"""
import os, base64
PATCHES = {
    'scrapers/github_scraper.py': '',
    'scrapers/twitter_scraper.py': '',
}
for p, b in PATCHES.items():
    d = os.path.dirname(p)
    if d: os.makedirs(d, exist_ok=True)
    open(p, "wb").write(base64.b64decode(b))
    print(f"  ✅ {p}")
print("\n✅ fix4 done!")
print("Jalankan: git pull --rebase origin main && git add . && git commit -m \"fix: spam filter + url resolve\" && git push")